module top_module(
    input in,
    output reg out,  // Change the output declaration to reg
    input clk
);reg unused_prev_in;

    always @(posedge clk) begin
        if (in && !unused_prev_in) begin
            out <= 1'b1;
        end else begin
            out <= 1'b0;
        end
        unused_prev_in <= in;
    end

endmodule
